# these are the celltypes in the dataset, this function groups in coarse categories
function hemibrain_coarse_type(t::Union{AbstractString, Nothing, Missing})
    # if t === nothing || t == "" || t === missing
    #     return "Unknown"
    if t === nothing || t === missing
        return "Unknown"
    elseif t == ""
        return "Unknown"

        # --- Dopaminergic (DANs) ---
    elseif occursin(r"^(PPL107|PPL108|PPL2\d|PPM\d|PAL\d)", t)
        return "Dopaminergic"

    # --- Central Complex ---
    elseif occursin(r"^(Delta7|vDelta|hDelta|EL|EPG|EPGt|ER(1|2|3|4|5|6)|ExR(1|2|3|4|5|6|7|8)|FB\d|FC\d|FR\d|FS\d|IbSpsP|LCNO|LNO|GLNO|LPsP|P\d|PEG|PEN|PFG|PFL|PFN|PFR|SA|SAF|SpsP)", t)
        return "Central Complex"

    # --- Mushroom Body ---
    elseif occursin(r"^(KC|MBON|APL|DPM|MB-C1|PAM|PPL1(0[1-6])?)", t)
        return "Mushroom Body"

    # --- Octopaminergic ---
    elseif occursin(r"^OA-", t)
        return "Octopaminergic"

    # --- Serotonergic ---
    elseif occursin(r"^(5-HT|CSD)", t)
        return "Serotonergic"

    # --- Peptidergic ---
    elseif occursin(r"^(AstA|CRZ|DSK|NPF|PI\d|SIFa)", t)
        return "Peptidergic"

    # --- Circadian ---
    elseif occursin(r"^(DN1|l-LNv|s-LNv|LNd|LPN)", t)
        return "Circadian"

    # --- Fruitless ---
    elseif occursin(r"^(aDT|aIPg|aSP|pC1|ovi|SAG|vpo)", t)
        return "Fruitless"

    # --- Optic lobe / visual ---
    elseif occursin(r"^(aMe|CT|LC|LLPC|LPC|LPLC|LT|MC|DCH|H\d|HSN|HSE|HSS|VS|VCH|Li\d|HBeyelet)", t)
        return "Visual projection and Optic lobe"

    # --- Descending neurons ---
    elseif occursin(r"^DN", t) || t in ["Giant_Fiber","MDN", "Giant Fiber"]
        return "Descending"

    # --- Sensory (ORN/TRN/HRN/JO/OCG) ---
    elseif occursin(r"^(ORN|TRN|HRN|JO-|OCG)", t)
        return "Sensory"

    # --- Antennal lobe ---
    elseif occursin(r"^(D_|DA|DC|DL|DM|V_ilPN|V_l2PN|DP|VA|VC|v2LN|VL|l2LN|VM|VP|M_|MZ_|Z_|lLN|vLN|il\d|mAL|AL-|ALBN|ALIN)", t)
        return "Antennal Lobe"

    # --- Lateral Horn ---
    elseif occursin(r"^LH", t)
        return "Lateral Horn"

    # --- Anterior Optic Tubercle ---
    elseif occursin(r"^(AOTU|TuBu|TuTu)", t)
        return "Anterior optic tubercle"

    # --- Antler ---
    elseif occursin(r"^ATL", t)
        return "Antler"

    # --- AVLP ---
    elseif occursin(r"^AVLP", t)
        return "Anterior ventrolateral protocerebrum"

    # --- Clamp ---
    elseif occursin(r"^CL", t)
        return "Clamp"

    # --- Crepine ---
    elseif occursin(r"^CRE", t)
        return "Crepine"

    # --- Inferior Bridge ---
    elseif occursin(r"^IB", t)
        return "Inferior Bridge"

    # --- Lateral Accessory Lobe ---
    elseif occursin(r"^LAL", t)
        return "Lateral accessory lobe "

    # --- Posterior Lateral Protocerebrum ---
    elseif occursin(r"^PLP", t)
        return "Posterior lateral protocerebrum"

    # --- Posterior Slope ---
    elseif occursin(r"^PS", t)
        return "Posterior Slope"

    # --- PVLP ---
    elseif occursin(r"^PVLP", t)
        return "Posterior ventrolateral protocerebrum"

    # --- Saddle / AMMC ---
    elseif occursin(r"^(SAD|AMMC)", t)
        return "Saddle and Antennal mechanosensory and Motor center "

    # --- Superior Lateral Protocerebrum ---
    elseif occursin(r"^SLP", t)
        return "Superior lateral protocerebrum"

    # --- Superior Intermediate Protocerebrum ---
    elseif occursin(r"^SIP", t)
        return "Superior intermediate protocerebrum"

    # --- Superior Medial Protocerebrum ---
    elseif occursin(r"^(SMP|DGI)", t)
        return "Superior medial protocerebrum"

    # --- Vest ---
    elseif occursin(r"^VES", t)
        return "Vest "

    # --- Wedge ---
    elseif occursin(r"^WED", t)
        return "Wedge"

    else
        return "Uncategorised"
    end
end

coarse_celltypes = [hemibrain_coarse_type(t) for t in unique_types]
unique_coarse_types = unique(coarse_celltypes)


# celltypes for our subnetworks
coarse_types_conn = [hemibrain_coarse_type.(group) for group in mapped_types]

weighted_tv_conn_adult = deepcopy(weighted_tv_conn[12:end])


function subnet_celltype_importance(coarse_types_conn, weighted_tv_conn_adult)
    n_subnets = length(coarse_types_conn)
    n_tasks = length(weighted_tv_conn_adult[1])
    subnet_matrices = Vector{Any}(undef, n_subnets)

    for sid in 1:n_subnets
        types = coarse_types_conn[sid]          # celltypes for this subnetwork
        task_data = weighted_tv_conn_adult[sid] # 8 tasks × 30 instantiations × neurons
        celltypes = unique(types)
        n_types = length(celltypes)

        # matrix: tasks × celltypes
        mat = zeros(n_tasks, n_types)

        for tid in 1:n_tasks
            inst_arrays = task_data[tid]                  # 30 arrays of length n_neurons
            all_neuron_vals = reduce(vcat, inst_arrays)  # flatten to length n_neurons * 30
            n_inst = length(inst_arrays)
            all_types = repeat(types, inner=n_inst)      # repeat neuron types per instantiation

            for (j, ct) in enumerate(celltypes)
                mat[tid, j] = mean(all_neuron_vals[all_types .== ct])
            end
        end

        subnet_matrices[sid] = (celltypes, mat)
    end

    return subnet_matrices
end


subnet_matrices_adult = subnet_celltype_importance(coarse_types_conn, weighted_tv_conn_adult)
n_subnets_adult = length(subnet_matrices_adult)


heatmaps_adults = []

for id in 1:28
    celltypes = subnet_matrices_adult[id][1]
    mat = subnet_matrices_adult[id][2]

    #sort alphabetically
    perm = sortperm(celltypes)
    celltypes_sorted = celltypes[perm]
    mat_sorted = mat[:, perm]

    # plot normalised matrix
    h = heatmap(
        mat_sorted ./ sum(mat_sorted, dims=2),
        yflip = true, color = :viridis, colorbar = false,
        title = "Subnetwork $id",
        yticks = 1:size(mat_sorted, 1),
        xticks = (1:length(celltypes_sorted), celltypes_sorted),
        xrotation = 90
    )
    push!(heatmaps_adults, h)
end

p = plot(
