)



#############################
# make overall heatmap

function global_celltype_importance(coarse_types_conn, weighted_tv_conn_adult)
    n_subnets = length(coarse_types_conn)
    n_tasks = length(weighted_tv_conn_adult[1])

    # Collect all unique celltypes across all subnetworks
    all_celltypes = unique(vcat(coarse_types_conn...))
    n_types = length(all_celltypes)

    # initialize matrix: tasks × global celltypes
    mat = zeros(n_tasks, n_types)

    # accumulate values and counts per celltype
    counts = zeros(Int, n_types)

    for sid in 1:n_subnets
        types = coarse_types_conn[sid]          # celltypes in this subnetwork
        task_data = weighted_tv_conn_adult[sid] # 8 tasks × 30 inst × neurons
        n_neurons = length(types)

        for tid in 1:n_tasks
            inst_arrays = task_data[tid]
            all_neuron_vals = reduce(vcat, inst_arrays)  # length n_neurons * 30
            n_inst = length(inst_arrays)
            all_types = repeat(types, inner=n_inst)

            for (j, ct) in enumerate(all_celltypes)
                v = all_neuron_vals[all_types .== ct]
                mat[tid,j] += sum(v)
                counts[j] += length(v)
            end
        end
    end

    # divide by counts to get mean
    for j in 1:n_types
        if counts[j] > 0
            mat[:,j] ./= counts[j]
        end
    end

    return all_celltypes, mat
end



global_celltypes_adult, global_mat_adult = global_celltype_importance(coarse_types_conn, weighted_tv_conn_adult)

summary_heatmap_adult = heatmap(
    global_mat_adult ./ sum(global_mat_adult, dims=2),  # row-normalize
    xticks = (1:length(global_celltypes_adult), global_celltypes_adult),
    yticks = (1:size(global_mat_adult,1), ["Task $i" for i in 1:size(global_mat_adult,1)]),
    xrotation=90, yflip=true, rightmargin=5mm,
    xlabel="Cell Type", ylabel="Task",size = (600, 700),
    title= "Mean Weighted Task Variance over All Cell Types",tickfontsize=12,labelfontsize=14,
    color=:viridis
)



